// TwoFingerNav.tsx
import React from 'react';
import {StyleSheet, View, useWindowDimensions} from 'react-native';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import Animated, {useSharedValue, useAnimatedStyle, withSpring, runOnJS} from 'react-native-reanimated';
import * as Haptics from 'expo-haptics';
export function TwoFingerNav({screens, index, onChange}: {screens: React.ReactNode[]; index: number; onChange: (i: number) => void}) {
  const {width: SW} = useWindowDimensions();
  const x = useSharedValue(-index * SW);
  const ctx = useSharedValue(0);
  React.useEffect(() => { x.value = withSpring(-index * SW, {damping: 22, stiffness: 240}); }, [index]);
  const commit = (next: number) => { Haptics.selectionAsync(); onChange(next); };
  const pan = Gesture.Pan().minPointers(2).onStart(() => { ctx.value = x.value; }).onUpdate(e => { x.value = ctx.value + e.translationX; }).onEnd(e => { const proj = x.value + e.velocityX * 0.1; let target = -index * SW; if (proj < -index * SW - SW * 0.3 && index < screens.length - 1) target = -(index + 1) * SW; else if (proj > -index * SW + SW * 0.3 && index > 0) target = -(index - 1) * SW; x.value = withSpring(target, {damping: 22, stiffness: 240}); if (target !== -index * SW) runOnJS(commit)(-target / SW); });
  const style = useAnimatedStyle(() => ({transform: [{translateX: x.value}]}));
  return (<GestureDetector gesture={pan}><Animated.View style={[{flex:1, flexDirection:'row', width: SW * screens.length}, style]}>{screens.map((s2, i) => <View key={i} style={{width: SW}}>{s2}</View>)}</Animated.View></GestureDetector>);
}

