import React from 'react';
import {StyleSheet, View, Text} from 'react-native';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import Animated, {useSharedValue, useAnimatedStyle, withSpring, runOnJS, interpolate, Extrapolation} from 'react-native-reanimated';
import * as Haptics from 'expo-haptics';
export function HoldRecordMic({onStart, onCommit, onCancel}: {onStart: () => void; onCommit: () => void; onCancel: () => void}) {
  const x = useSharedValue(0); const active = useSharedValue(false);
  const start = () => { Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium); onStart(); };
  const commit = () => { Haptics.selectionAsync(); onCommit(); };
  const cancel = () => { Haptics.notificationAsync(Haptics.NotificationFeedbackType.Warning); onCancel(); };
  const longPress = Gesture.LongPress().minDuration(150).onStart(() => { active.value = true; runOnJS(start)(); });
  const pan = Gesture.Pan().onUpdate(e => { if (active.value) x.value = Math.min(0, e.translationX); }).onEnd(() => { active.value = false; if (x.value < -120) { runOnJS(cancel)(); } else { runOnJS(commit)(); } x.value = withSpring(0); });
  const gesture = Gesture.Simultaneous(longPress, pan);
  const micStyle = useAnimatedStyle(() => ({transform: [{translateX: x.value}, {scale: 1 + Math.abs(x.value) * 0.001}]}));
  const cancelStyle = useAnimatedStyle(() => ({opacity: interpolate(-x.value, [40, 120], [0, 1], Extrapolation.CLAMP)}));
  return (<View style={s.row}><Animated.View style={[s.cancel, cancelStyle]}><Text style={s.cancelText}>{'← Slide to cancel'}</Text></Animated.View><GestureDetector gesture={gesture}><Animated.View style={[s.mic, micStyle]}><Text style={s.micGlyph}>{'🎤'}</Text></Animated.View></GestureDetector></View>);
}
const s = StyleSheet.create({row:{flexDirection:'row', alignItems:'center', justifyContent:'flex-end', padding:16}, cancel:{position:'absolute', left:24}, cancelText:{color:'#8E8E93'}, mic:{width:56, height:56, borderRadius:28, backgroundColor:'#FF453A', alignItems:'center', justifyContent:'center'}, micGlyph:{fontSize:26}});

