import React, {useEffect} from 'react';
import {StyleSheet, View} from 'react-native';
import {Canvas, Circle, Group} from '@shopify/react-native-skia';
import {Easing, useSharedValue, withRepeat, withTiming} from 'react-native-reanimated';
export function OrbitLoader({size = 48, color = '#0A84FF'}: {size?: number; color?: string}) {
  const phase = useSharedValue(0);
  useEffect(() => { phase.value = withRepeat(withTiming(1, {duration: 900, easing: Easing.linear}), -1, false); }, [phase]);
  const r = size / 3; const cx = size / 2; const cy = size / 2;
  const dots = [0, 1, 2].map((i) => ({x: cx + Math.cos(i * Math.PI * 2 / 3) * r, y: cy + Math.sin(i * Math.PI * 2 / 3) * r, opacity: 0.45 + i * 0.2}));
  return <View style={styles.wrap} accessibilityRole="progressbar" accessibilityLabel="Loading"><Canvas style={{width: size, height: size}}><Group transform={[{rotate: phase.value * Math.PI * 2}, {translateX: cx}, {translateY: cy}]}>{dots.map((dot, i) => <Circle key={i} cx={dot.x - cx} cy={dot.y - cy} r={4 + i} color={color} opacity={dot.opacity} />)}</Group></Canvas></View>;
}
const styles = StyleSheet.create({wrap: {alignItems: 'center', justifyContent: 'center'}});

